INSERT INTO `courses` (`id`, `subject_id`, `course_name`, `description`) VALUES
(10, 1, 'Grammar Basics', 'Learn the fundamental rules of English grammar including nouns, verbs, adjectives, and sentence structure.'),
(11, 1, 'Vocabulary Building', 'Expand your English vocabulary through common words, meanings, and practical usage.'),
(12, 1, 'Reading Skills', 'Develop reading comprehension skills through passages, analysis, and understanding key ideas.'),
(13, 1, 'Writing Skills', 'Learn how to write clear sentences, paragraphs, essays, and formal English content.'),
(14, 1, 'Communication Skills', 'Improve speaking, listening, and conversational English for real-life situations.'),
(15, 2, 'Numbers and Operations', 'Learn number systems, arithmetic operations, and basic mathematical calculations.'),
(16, 2, 'Algebra Fundamentals', 'Understand variables, equations, expressions, and algebraic problem solving.'),
(17, 2, 'Geometry Basics', 'Learn shapes, angles, lines, area, perimeter, and geometric reasoning.'),
(18, 2, 'Statistics and Data', 'Explore data collection, graphs, averages, and basic statistical analysis.'),
(19, 2, 'Introduction to Calculus', 'Learn limits, rates of change, and the foundations of calculus.'),
(20, 3, 'Introduction to Science', 'Learn the basic concepts of science, scientific methods, and observation skills.'),
(21, 3, 'Physics Fundamentals', 'Explore motion, forces, energy, and the basic laws of physics.'),
(22, 3, 'Chemistry Basics', 'Understand matter, atoms, elements, compounds, and chemical reactions.'),
(23, 3, 'Biology Fundamentals', 'Study living organisms, cells, body systems, and ecosystems.'),
(24, 3, 'Environmental Science', 'Learn about the environment, natural resources, pollution, and sustainability.'),
(34, 4, 'English', 'Develop advanced reading, writing, grammar, vocabulary, comprehension, and communication skills required for Grade 12 students.'),
(35, 4, 'Mathematics', 'Study algebra, trigonometry, calculus fundamentals, problem-solving techniques, and mathematical reasoning for higher education preparation.'),
(36, 4, 'Chemistry', 'Learn chemical reactions, atomic structure, organic chemistry, laboratory concepts, and practical applications of chemistry in daily life.'),
(37, 4, 'Biology', 'Explore living organisms, human body systems, genetics, ecology, evolution, and biological processes through theoretical and practical learning.'),
(38, 4, 'Economics', 'Understand economic principles, market systems, supply and demand, national economies, and financial decision-making concepts.'),
(39, 4, 'Physics', 'Study motion, forces, energy, electricity, waves, modern physics, and the scientific principles governing the physical world.');

